import os
from llama_cloud import LlamaCloud

def cleanup_all():
    client = LlamaCloud(api_key=os.environ["LLAMA_CLOUD_API_KEY"])
    projects = client.projects.list()
    for p in projects:
        print(f"Checking Project: {p.name} ({p.id})")
        pipelines = client.pipelines.list(project_id=p.id)
        for pipe in pipelines:
            print(f"  Deleting Pipeline: {pipe.name} ({pipe.id})")
            client.pipelines.delete(pipe.id)

if __name__ == "__main__":
    cleanup_all()

